export const sqActivities: Activity[] = [
  {"id":"sq-nature-journaling","title":"Nature Journaling","altNames":["Field Journal","Naturalist Notebook","Sketch & Note"],"type":"Quiet","place":"Both","ageMin":9,"ageMax":18,"durationMin":30,"groupMin":null,"groupMax":null,"energy":1,"prep":"Low","blurb":"Campers slow down and become naturalists, capturing one patch of the world in words, sketches, and questions.","materials":["Assorted paper, 3-4 sheets per camper (folded/stapled into a booklet)","Pencils or pens, 1 per camper","Markers and crayons to share","Masking tape for booklet spines","Optional: clipboards or cardboard squares as lap-desks"],"materialTags":["Paper","Markers","Crayons","Masking tape","Cardboard"],"steps":["Fold 3-4 sheets of paper in half and tape the spine to make each camper a pocket journal, then have them write the date and a temperature/weather guess on page one.","Lead everyone to an outdoor spot (or window/plant indoors) and have each camper claim a small patch no bigger than a hula hoop to study.","Set three columns or prompts on a page: 'I notice...', 'I wonder...', and 'It reminds me of...' and ask campers to fill each with at least two entries.","Give five silent minutes to sketch one thing in their patch as carefully as they can, drawing what they actually see rather than a symbol.","Have campers add labels, arrows, and measurements (in finger-widths or pencil-lengths) to turn the sketch into a real field record.","Gather in a circle and invite a few volunteers to share their best 'I wonder' question, listing the questions on a shared sheet to revisit later."],"notes":"Keep groups loose and spread campers out so nobody copies a neighbor's patch. Pacing matters: protect the silent sketch minutes by counting down out loud, since the urge to chat is strong. To scale up for grades 7-12, require a measured cross-section, a labeled diagram with a scale bar, and a written hypothesis answering one of their 'I wonder' questions like a true field scientist.","safety":"Set a clear boundary line for the study patches so campers stay in sight, and remind them not to taste or pick anything, especially unknown berries, mushrooms, or shiny three-leaf plants.","ages":["g46","g79","g1012"],"rating":0,"links":[{"label":"Rustic Pathways: 26 summer camp activities","url":"https://rusticpathways.com/blog/summer-camp-activities"}],"variations":["Theme the journal around a single sense (only sounds, or only textures) so campers practice noticing one channel at a time.","Run a 'same spot, four times' version where campers revisit the exact patch each day of the week and chart what changed.","For grades 7-12, require a quantitative page: tally counts, sketch a scaled diagram with a measurement key, and write a testable hypothesis about the patch.","Turn it into a swap where campers trade journals and try to find the patch a partner described using only their notes."],"subsets":[["Stack and fold the sheets together before taping so pages line up.","Number the pages in a corner."],[],["Model one example aloud so they hear the difference between 'notice' and 'wonder'."],["Tell them wobbly lines are fine; accuracy beats neatness."],["Show how to measure in finger-widths if no ruler is handy."],[]]},
  {"id":"sq-sit-spot-listening","title":"Sit Spot Listening","altNames":["Sit Spot","Listening Spot","Silent Sit","Owl Ears"],"type":"Quiet","place":"Both","ageMin":9,"ageMax":18,"durationMin":15,"groupMin":null,"groupMax":null,"energy":1,"prep":"None","blurb":"Each camper finds a private patch of ground and goes still until the world starts talking back.","materials":["Optional: assorted paper and a pencil per camper for a sound tally","Optional: a cushion, towel, or piece of cardboard to sit on"],"materialTags":["Paper","Cardboard"],"steps":["Explain 'owl ears': cup your hands behind your ears to hear how it amplifies sound, then drop them and try to hold that level of attention.","Spread campers out so each has a personal sit spot a body-length from anyone else, all facing slightly different directions.","Start a silent stretch of three to five minutes where the only job is to listen and count every distinct sound they can detect.","When time is up, have campers raise the number of sounds they heard on their fingers without speaking, then take a slow breath together.","Go around the circle and let each camper name just one sound nobody else has claimed yet, stretching the group to find quieter and quieter ones.","Close by asking which sound was the farthest away and which was the closest, mapping the soundscape from near to far."],"notes":"This is a perfect rest-hour reset after a loud activity; dim the energy by lowering your own voice as you give directions. Younger campers may need a clear 'no talking, no touching neighbors' rule and a visible timer. For grades 7-12, lengthen the silence to eight minutes and ask them to estimate compass direction and distance for each sound, turning it into an auditory mapping exercise.","safety":"Choose sit spots away from ant hills, poison-ivy edges, and hot pavement, and keep the whole group within a single glance so no camper drifts out of sight.","ages":["g46","g79","g1012"],"rating":0,"links":[{"label":"Rustic Pathways: nature walk & observation","url":"https://rusticpathways.com/blog/summer-camp-activities"}],"variations":["Add a 'sound map' page where campers put themselves in the center and draw each sound as a symbol in the direction it came from.","Run a closed-eyes 'sound chain' indoors where you make tiny noises (tearing paper, tapping a cup) and campers guess each one.","For grades 7-12, require a timed sound log with direction and rough distance for every noise, then have them graph quiet versus busy stretches.","Pair campers as 'echo partners' who afterward try to recreate three sounds with their mouths and let the partner identify them."],"subsets":[["Have everyone try owl ears at once so they feel the difference."],[],["Hold up fingers counting down the final ten seconds silently."],[],["If a sound is already taken, they must find a new one, which keeps ears working."],[]]},
  {"id":"sq-sound-mapping","title":"Sound Mapping","altNames":["Sound Map","Audio Compass","Listening Map"],"type":"Quiet","place":"Both","ageMin":9,"ageMax":18,"durationMin":30,"groupMin":null,"groupMax":null,"energy":1,"prep":"Low","blurb":"Campers sit at the center of their own map and plot every sound by where it comes from and how far away it is.","materials":["Assorted paper, 1 sheet per camper","Pencils or pens, 1 per camper","Markers to share for color-coding","Clipboards or cardboard lap-desks, 1 per camper"],"materialTags":["Paper","Markers","Cardboard"],"steps":["Have each camper draw a small symbol of themselves in the center of their page; this is where they are sitting.","Explain that the top of the page is the direction they face and the edges are 'far away,' so a sound's symbol goes nearer or farther from center by distance.","Settle the group into a few minutes of silence and have campers mark each sound with a quick symbol (zig-zag for a bird, wavy lines for wind) in its direction and distance.","After the listening window, give two minutes to color-code symbols: one color for nature sounds, another for human-made sounds.","Have campers count and write the totals for each color in a corner of the map.","Finish by having partners trade maps and try to guess, from the symbols alone, what their partner's loudest and most distant sounds were."],"notes":"Demonstrate one symbol on a big sheet first so campers understand symbols beat words for speed. Spread the group out and keep the listening window genuinely silent; the map only works if they actually hear before they draw. To scale up for grades 7-12, have them add a rough scale ('each ring = 20 steps'), a compass rose with real cardinal directions, and a written comparison of the nature-versus-human sound ratio between two different locations.","safety":"Keep clipboards and pencils out from underfoot so nobody trips while settling in, and pick a sit area free of ant trails and sun-baked metal that could burn bare legs.","ages":["g46","g79","g1012"],"rating":0,"links":[{"label":"Little Bins for Little Hands: nature activities","url":"https://littlebinsforlittlehands.com/summer-camp-activities/"}],"variations":["Make two maps in two spots (a shady tree versus an open field) and discuss which place was 'louder' and why.","Run a quiet 'symbol legend' round first where the group invents shared symbols before mapping, building a common visual language.","For grades 7-12, require a compass rose, a step-counted scale, and a written analysis comparing nature-to-human sound ratios across two sites.","Do a fixed-target version where you place a hidden sound (a wind-up timer, a tapping counselor) and campers must pinpoint its direction on the map."],"subsets":[[],["Draw a simple example on a big sheet so they copy the format."],["Keep symbols tiny and fast; this is not a drawing contest."],["Suggest blue for nature, red for human-made to keep it consistent."],[],[]]},
  {"id":"sq-cloud-watching","title":"Cloud Watching & Sky Stories","altNames":["Cloud Gazing","Sky Stories","Cloud Shapes"],"type":"Quiet","place":"Outside","ageMin":9,"ageMax":15,"durationMin":15,"groupMin":null,"groupMax":null,"energy":1,"prep":"None","blurb":"Lie back, watch the clouds drift, and let the sky become a slow-motion storybook.","materials":["A grassy or shaded spot to lie down","Optional: towels, cardboard, or paper bags flattened as ground mats","Optional: assorted paper and pencils for sketching or story notes"],"materialTags":["Cardboard","Paper","Paper bags"],"steps":["Lead the group to a clear-sky spot and have each camper lie back or recline with their own bit of space and a flattened mat under them.","Open with a full minute of pure watching: no talking, just letting eyes follow the clouds as they move and morph.","Invite campers to whisper to themselves what shapes they see, then point one out silently to the sky so neighbors can hunt for it too.","Have each camper pick one cloud and watch it long enough to describe how it changes shape over thirty seconds.","Go around and let volunteers share a one-line 'sky story' starting with 'Once there was a cloud that...' building on the shapes they spotted.","Close by guessing together whether the clouds are moving fast or slow and which direction the wind is pushing them."],"notes":"Best on a partly cloudy day; check the forecast and have a backup if the sky is flat blue or fully overcast. Keep it short and unhurried, and resist the urge to over-direct, since the magic is in the drifting. For grades 7-9, layer in real cloud types (puffy cumulus, wispy cirrus, flat stratus) and have them predict the next hour's weather from what they observe.","safety":"Absolutely no staring at or near the sun; position the group so the sun is behind them, and use mats or shade to keep campers off hot ground.","ages":["g46","g79"],"rating":0,"links":[{"label":"Little Bins for Little Hands: nature activities","url":"https://littlebinsforlittlehands.com/summer-camp-activities/"}],"variations":["Add a sketch round where campers draw the most interesting cloud and label it with the made-up creature it became.","Run a 'cloud relay story' where each camper adds one sentence to a group tale inspired by the next cloud that drifts in.","For grades 7-9, turn it into a weather lab: identify cloud types, estimate cloud cover in eighths, and make a written one-hour forecast to check later.","Pair campers as 'cloud detectives' who must both spot and agree on a shape before it dissolves, racing the wind."],"subsets":[["Hand out mats so campers aren't lying directly on damp or hot ground."],[],[],["Point out that fast-changing clouds are the most fun to track."],[],[]]},
  {"id":"sq-mindfulness-breathing","title":"Mindfulness Breathing Journey","altNames":["Calm Breathing","Belly Breathing","Breath Break","Five-Finger Breathing"],"type":"Quiet","place":"Both","ageMin":9,"ageMax":18,"durationMin":15,"groupMin":null,"groupMax":null,"energy":1,"prep":"None","blurb":"A guided breathing reset that takes a wound-up group from rowdy to calm in ten minutes flat.","materials":["Optional: a small playground ball or balloon per camper to feel the rise and fall of breath","Optional: towels or cardboard to sit on","A quiet space"],"materialTags":["Playground balls","Balloons","Cardboard"],"steps":["Have campers sit or lie comfortably with space around them, hands resting on their belly so they can feel it move.","Lead 'flower and candle' breathing: breathe in slowly as if smelling a flower, then breathe out slowly as if cooling soup, repeating four times.","Switch to 'five-finger breathing' where campers trace one hand with the other finger, breathing in up each finger and out down the other side.","Guide a 'body scan' by naming relaxed body parts from toes to head, asking campers to let each part go heavy and still.","Add a 'square breath' for older campers: in for four counts, hold four, out four, hold four, repeated a few rounds.","Bring the group gently back by having everyone wiggle fingers and toes, take one big breath, and open their eyes."],"notes":"Use this as a transition tool before rest hour, after a conflict, or to settle a hyped-up cabin; your calm, slow voice is the real instrument. Some campers giggle at first, so acknowledge it and keep going rather than stopping. For grades 7-12, teach the science (the relaxation response, heart rate slowing) and let them lead a round for the group, building real self-regulation skills.","safety":"Make breath holds optional and short, and tell campers to skip any hold and breathe normally if they feel dizzy or lightheaded at any point.","ages":["g46","g79","g1012"],"rating":0,"media":[{"title":"Five Finger Breathing — guided breathing exercise for kids (video tutorial)","url":"https://www.youtube.com/watch?v=HQVZgpyVQ78"}],"links":[{"label":"S&S Blog: Kindness & calm camp themes","url":"https://www.ssww.com/blog/top-10-summer-camp-themes-creative-engaging-activity-ideas/"}],"variations":["Use a balloon as a 'breath-o-meter': inflate it slowly on each exhale so campers see their breath made visible.","Do 'bumblebee breath' where campers hum on the exhale, feeling the buzz, which especially settles younger groups.","For grades 7-12, teach box breathing and the underlying relaxation-response science, then have a camper guide a full round solo.","Pair it with the sit-spot activity as a two-minute warm-up before silent listening to deepen focus."],"subsets":[["Let campers choose sitting or lying down, whichever feels calmer."],["Model the flower-and-candle motion with your own hands."],["Trace slowly so the breath matches the finger movement."],[],["Keep counts steady and slow; rushing defeats the purpose."],[]]},
  {"id":"sq-gratitude-rocks","title":"Gratitude Rocks","altNames":["Kindness Stones","Story Stones","Painted Gratitude Rocks","Thankful Rocks"],"type":"Craft","place":"Both","ageMin":9,"ageMax":18,"durationMin":45,"groupMin":null,"groupMax":null,"energy":1,"prep":"Medium","blurb":"Campers paint smooth stones with one thing they're grateful for, then hide them as tiny gifts for whoever finds them next.","materials":["Smooth flat rocks, 1-2 per camper (collected ahead or on a nature walk)","Paint in several colors","Paintbrushes, 1 per camper","Fine-tip markers for words and details","Paper towels for cleanup","Water cups for rinsing brushes","Newspaper or assorted paper to cover tables"],"materialTags":["Paint","Paintbrushes","Markers","Paper towels","Water source","Paper"],"steps":["Cover the tables with paper and give each camper a clean, dry rock and a moment to think of one specific thing they're grateful for.","Have campers paint a solid base coat over their rock and set it aside to dry for a few minutes while they plan their design.","Once the base is touch-dry, paint or marker a small picture or symbol of their gratitude onto the rock.","Add the gratitude word or a short phrase with a fine-tip marker, keeping it readable.","Let the rocks dry fully on a labeled paper towel while campers wash brushes and wipe down their space.","Close in a circle where each camper shares their rock's gratitude in one sentence, then decide together whether to keep them or hide them around camp for others to discover."],"notes":"Collect rocks the day before or fold it into a short nature walk; smooth river-style rocks paint best. Build in real drying time between coats or designs smear, so stagger campers and use the wait for the sharing circle. To scale up for grades 7-12, push for layered designs, dot-painting patterns, or a longer written reflection, and let them organize a camp-wide 'kindness rock hunt' for younger groups.","safety":"Remind campers that rocks are for painting and hiding, never for throwing, and keep brushes and paint water away from mouths since some campers will absentmindedly chew brush handles.","ages":["g46","g79","g1012"],"rating":0,"links":[{"label":"A Complete Guide to Rock Painting and Spreading Kindness Through Art","url":"https://inspirekindness.com/blog/rock-painting"},{"label":"Rustic Pathways: painted rocks & kindness ideas","url":"https://rusticpathways.com/blog/summer-camp-activities"},{"label":"Our Days Outside: classic summer camp crafts","url":"https://ourdaysoutside.com/15-classic-summer-camp-crafts-for-kids/"}],"variations":["Make 'story stones' instead by painting simple symbols (a moon, a wave, a tree) that campers later combine to tell improvised stories.","Run a 'compliment rock' version where each rock names something kind about a specific person and is given to them.","For grades 7-12, require a multi-step technique like dot-mandala patterns or layered backgrounds plus a written gratitude reflection on the back.","Turn the finished rocks into a permanent 'gratitude garden' border or hide them on trails as a kindness hunt for the next session's campers."],"subsets":[["Have campers wipe any dust off the rock so paint sticks."],["Thin coats dry faster than one thick gloppy coat."],[],["Suggest pencil-light planning before committing in marker."],["Write each camper's name on their drying spot to avoid mix-ups."],[]]},
  {"id":"sq-observation-memory-tray","title":"Observation Memory Tray (Kim's Game)","altNames":["Kim's Game","Memory Tray","What's Missing","Spy Memory Game"],"type":"Quiet","place":"Both","ageMin":9,"ageMax":18,"durationMin":15,"groupMin":2,"groupMax":16,"energy":1,"prep":"Low","blurb":"Study a tray of objects, then test your detective memory as items vanish and rearrange.","materials":["A tray, paper plate, or piece of cardboard as the display surface","15-20 small assorted objects (markers, beads, clothespins, a balloon, a sponge, a cup, etc.)","A paper bag or towel to cover the tray","Assorted paper and pencils, 1 per camper for answers"],"materialTags":["Cardboard","Paper plates","Markers","Pony beads","Paper bags","Paper"],"steps":["Arrange 15-20 small objects on the tray and let the group study it silently for one full minute, no touching, no talking.","Cover the tray with a towel or paper bag and have campers write down or whisper to a partner as many objects as they can recall.","Reveal the tray and tally who remembered the most, celebrating the camper with the longest correct list.","Play round two: cover the tray, secretly remove one or two objects, then uncover and challenge campers to name what's missing.","Play round three: this time rearrange or swap objects instead of removing them, and have campers spot what moved.","Wrap up by talking about which memory tricks helped (grouping objects, making a story, picturing the layout) and let a camper set up the next tray."],"notes":"Keep objects varied in size and color so they're memorable, and run rounds quickly to keep energy up despite it being a 'quiet' game. Younger campers do better with 10-12 objects; add more to raise difficulty. To scale up for grades 7-12, jump to 25+ objects, shorten the study window to 30 seconds, and add 'swap two and change one' rounds where they must report every single change.","safety":"Avoid sharp or chokeable items on the tray, and if you use small beads keep them counted and collected at the end so none roll loose underfoot.","ages":["g46","g79","g1012"],"rating":0,"links":[{"label":"CampMinder: 27 summer camp activities","url":"https://campminder.com/resources/27-summer-camp-activities-to-spice-up-the-summer-camp-atmosphere/"}],"variations":["Theme the tray (all nature objects, or all 'survival kit' items) to tie it into a daily camp theme.","Play 'team memory' where small groups pool their recall onto one shared list, encouraging cooperation.","For grades 7-12, use 25+ objects, a 30-second study window, and combine remove-rearrange-swap so they must catalog every change at once.","Run a 'nature trail' version where the 'tray' is a 10-foot stretch of trail and you remove or add a planted object between viewings."],"subsets":[["Spread objects out so none hide behind another."],["Decide in advance whether campers write or just remember."],[],["Pocket the removed items so campers can't peek at your hands."],["A subtle swap (two same-color objects) is sneaky and fun."],[]]},
  {"id":"sq-nature-scavenger-hunt","title":"Nature Scavenger Hunt with Riddle Twist","altNames":["Nature Hunt","Scavenger Hunt","Riddle Hunt","Nature Bingo"],"type":"Quiet","place":"Outside","ageMin":9,"ageMax":18,"durationMin":45,"groupMin":4,"groupMax":24,"energy":2,"prep":"Medium","blurb":"Teams decode riddles and hunt the grounds for natural treasures, observing closely instead of just grabbing.","materials":["A printed or hand-drawn hunt list/riddle card per team (on assorted paper)","Pencils, 1 per team","Paper bags, 1 per team for collected non-living finds","Markers to make the cards","Optional: a clipboard or cardboard backing per team"],"materialTags":["Paper","Paper bags","Markers","Cardboard"],"steps":["Write a hunt list ahead of time mixing plain items ('something rough') with riddles ('I'm a tree's fallen armor that crunches underfoot' for bark).","Split campers into small teams and give each a card, a pencil, and a paper bag, then set the boundaries and time limit clearly.","Send teams off to find and either collect (only fallen, non-living items) or observe-and-record (living things) each item on their list.","Require teams to note one observation for each find, like its color, texture, or where they found it, not just check the box.","Call everyone back at the time limit with a clear signal and have teams lay out their finds.","Review the list together, score one point per correct find plus a bonus for the best observation note, and crown the sharpest-eyed team."],"notes":"Pre-walk the route so your list actually matches what's findable, and keep teams to three or four for real participation. Stress a 'leave living things living' rule: photograph or sketch insects and flowers rather than collecting them. To scale up for grades 7-12, write tougher ecology riddles, require sketches with scientific descriptions, and add a 'classify your finds' sorting round (by texture, by living/non-living, by habitat).","safety":"Set firm boundaries and a recall signal, instruct campers to look but not touch unknown plants, mushrooms, or insects, and to never reach into holes, logs, or thick brush where stinging insects might nest.","ages":["g46","g79","g1012"],"rating":0,"links":[{"label":"Rustic Pathways: nature scavenger hunt with riddle twist","url":"https://rusticpathways.com/blog/summer-camp-activities"},{"label":"Little Bins for Little Hands: nature scavenger hunt","url":"https://littlebinsforlittlehands.com/summer-camp-activities/"}],"variations":["Make a 'rainbow hunt' where teams must find something natural in each color of the rainbow and arrange them in order.","Run it as nature bingo with a grid card, where the first team to complete a row, column, or full card wins.","For grades 7-12, write ecology-based riddles, require a labeled sketch and scientific description per find, and add a habitat-classification sorting round at the end.","Do a 'photo-only' eco version where nothing is collected and every find is documented by sketch or description, leaving the site untouched."],"subsets":[["Mix in two or three riddles per card to make it observation, not just collection."],["Walk the boundaries with a couple of cones so 'too far' is visible."],["Hand out bags only for fallen items; living finds get sketched."],["Show one example observation so campers know the expected detail."],["A whistle or raised arm works as the recall signal."],[]]},
  {"id":"sq-leaf-bark-observation","title":"Leaf & Bark Observation Lab","altNames":["Leaf Rubbings","Bark Rubbings","Texture Rubbings","Leaf Study"],"type":"Quiet","place":"Both","ageMin":9,"ageMax":18,"durationMin":45,"groupMin":null,"groupMax":null,"energy":1,"prep":"Low","blurb":"Campers become field botanists, capturing the hidden patterns of leaves and bark through rubbings and close observation.","materials":["Assorted paper, 3-4 sheets per camper","Crayons with wrappers peeled, several per table","Pencils for labeling","A collection of fallen leaves of different shapes","Markers for notes","Clipboards or cardboard backing, 1 per camper"],"materialTags":["Paper","Crayons","Markers","Cardboard"],"steps":["Collect a variety of fallen leaves and find a few trees with interesting bark; spread leaves on the tables vein-side up.","Show campers how to lay paper over a leaf and rub the side of a peeled crayon gently across it to reveal the veins.","Have each camper make rubbings of at least three different leaf shapes, labeling each with where they found it.","Move to a tree and have campers tape paper to the trunk and rub to capture the bark texture, then compare it to a different tree.","Back at the tables, give campers a hand lens of their fingers framing the leaf and ask them to write three observations: shape, edge (smooth or toothed), and vein pattern.","Create a class 'leaf gallery' by taping all the rubbings to a wall and grouping them by similar shapes or vein patterns."],"notes":"Peel the crayon wrappers ahead of time, since this is the step that eats the most minutes. Encourage light, even rubbing pressure; pressing too hard tears the paper and loses detail. To scale up for grades 7-12, introduce real botanical vocabulary (lobed, serrated, palmate, pinnate venation), have them key out and group leaves by these traits, and add a written comparison of two species' adaptations.","safety":"Hold leaves and bark to skin, not mouths, wash hands afterward in case of sap or pollen, and steer campers clear of any three-leaflet plants or fuzzy vines when collecting.","ages":["g46","g79","g1012"],"rating":0,"media":[{"title":"How to make crayon leaf rubbings — Huston-Brumbaugh Nature Center video tutorial","url":"https://www.youtube.com/watch?v=2zHH8YUXN-s"}],"links":[{"label":"Little Bins for Little Hands: leaf rubbings & nature art","url":"https://littlebinsforlittlehands.com/summer-camp-activities/"}],"variations":["Turn the rubbings into art by layering many leaves of different colors into a collage or framed scene.","Play 'match the leaf' where campers make a rubbing, then a partner must find the actual tree or leaf it came from.","For grades 7-12, teach botanical terms and have them build a simple leaf key, classifying species by edge, venation, and shape with written notes.","Make a 'texture book' that combines bark, leaf, sidewalk, and brick rubbings into a single bound booklet of patterns."],"subsets":[["Peel crayon wrappers in advance to save time."],["Demonstrate the gentle side-of-crayon stroke once for all."],["Remind them to label as they go, not after, so finds aren't mixed up."],["Tape paper firmly so it doesn't slip on the rough bark."],["Frame the leaf with fingers to focus attention like a lens."],["Group by shape or vein pattern so the gallery teaches sorting."]]},
  {"id":"sq-story-circle","title":"Story Circle Build-Along","altNames":["Group Storytelling","Story Chain","Round-Robin Story","Campfire Tales (Daytime)"],"type":"Quiet","place":"Both","ageMin":9,"ageMax":18,"durationMin":30,"groupMin":4,"groupMax":20,"energy":1,"prep":"Low","blurb":"One sentence at a time, the whole circle builds a wild, surprising tale that nobody could have written alone.","materials":["Optional: story prompt cards made from assorted paper","Optional: a 'talking object' to pass (a painted rock, a sponge ball, or a clothespin)","Markers to make prompt cards"],"materialTags":["Paper","Markers","Sponges"],"steps":["Seat campers in a circle and explain the one rule: when you hold the talking object, you add exactly one or two sentences, then pass it on.","Start the story yourself with a strong opening line, like 'The map said the treasure was buried under the loudest tree in the forest.'","Pass the object around the circle, with each camper continuing the story logically from the sentence before, no resetting or 'and then it was all a dream.'","Use prompt cards as wildcards: when you call 'twist!', the next camper draws a card (a new character, a problem, a setting) and must work it in.","Steer pacing so the story builds toward a problem in the middle and a resolution by the time the object returns to you.","Close the loop by adding the final line yourself, then have the circle vote on the best plot twist of the whole tale."],"notes":"Set a 'build, don't block' norm so campers add to ideas rather than killing them; redirect anyone who tries to end the story too early. Allow a quiet camper to pass once if needed, but invite them back in. To scale up for grades 7-12, require a consistent genre or constraint (mystery, must include a moral, no adjectives), assign rotating 'narrator roles,' and challenge them to plant clues early that pay off at the end.","safety":"Set a content guardrail up front (no gore, no naming real campers as villains, nothing that targets a person) and be ready to gently redirect a story that veers unkind.","ages":["g46","g79","g1012"],"rating":0,"links":[{"label":"CampMinder: storytelling prompts","url":"https://campminder.com/resources/27-summer-camp-activities-to-spice-up-the-summer-camp-atmosphere/"}],"variations":["Play 'three random words' where each camper must include three drawn words in their turn, forcing creativity.","Run a 'one-word story' speed round where every camper adds just a single word, building a sentence around the circle.","For grades 7-12, lock in a genre and a structural constraint (must plant a clue, must avoid a banned word) and require a satisfying twist that pays off early setups.","Make it a 'silent story' where the tale is built by passing a drawing and each camper adds one image instead of words."],"subsets":[["Choose a talking object that's easy to pass and pleasant to hold."],["A vivid, slightly odd opening line sparks the most ideas."],["Gently coach 'yes, and' so campers build rather than block."],["Pre-make a small stack of twist cards before the circle starts."],[],[]]},
  {"id":"sq-sensory-texture-hunt","title":"Sensory Texture Hunt & Touch Board","altNames":["Texture Hunt","Touch Board","Feely Board","Texture Walk"],"type":"Quiet","place":"Both","ageMin":9,"ageMax":15,"durationMin":45,"groupMin":null,"groupMax":null,"energy":1,"prep":"Medium","blurb":"Campers hunt for textures across camp, then glue their best finds onto a board that begs to be touched.","materials":["Cardboard, 1 piece per camper as the board base","Glue","Masking tape","Assorted textured items (sponges, yarn, sandpaper-rough bark, smooth leaves, foam scraps, crumpled paper)","Foam sheets and yarn from the supply closet","Markers for labeling","Paper bags, 1 per camper for collecting"],"materialTags":["Cardboard","Glue","Masking tape","Sponges","Yarn","Foam sheets","Markers","Paper bags"],"steps":["Give each camper a piece of cardboard and a paper bag, and explain they're collecting a variety of textures: rough, smooth, soft, bumpy, scratchy.","Lead a short texture walk where campers gather safe, fallen, or supply-closet items, naming the texture of each as they collect.","Back at the tables, have campers plan their board by laying items out in a row from smoothest to roughest before gluing.","Glue or tape each texture onto the cardboard, leaving room beside each for a label.","Label each texture with a marker word ('scratchy bark,' 'soft sponge') so the board can be read as well as felt.","Run a 'blind touch test' where partners close their eyes and try to identify each texture by feel alone, scoring a point per correct guess."],"notes":"Pre-stock a tray of supply-closet textures (foam, sponge, yarn, crumpled paper) so campers who find few natural textures still have plenty. Glue needs setting time, so order the steps so the blind test happens after a short cleanup wait. To scale up for grades 7-9, require the board to be organized by a real scale (Mohs-style hardness, or roughness ranking) and add a written description of what makes each texture feel the way it does.","safety":"Screen collected items for splinters, thorns, and sharp edges before gluing, keep glue away from eyes, and remind campers not to collect anything from plants they can't identify.","ages":["g46","g79"],"rating":0,"links":[{"label":"Little Bins for Little Hands: sensory & nature activities","url":"https://littlebinsforlittlehands.com/summer-camp-activities/"}],"variations":["Make a 'texture matching' game with two boards where campers must pair identical textures blindfolded.","Theme the board around one category (all-soft 'cozy board' or all-nature 'forest floor board') for a tighter design.","For grades 7-9, require the textures to be ranked on a measured roughness scale with written reasoning for each placement.","Turn finished boards into a camp 'texture trail' where blindfolded campers feel their way down a line of boards in order."],"subsets":[["Brainstorm the five texture words first so they know what to hunt."],["Model collecting only safe, fallen, or supply items."],["Arranging before gluing prevents a crowded, unlabelable board."],["A dab of glue or a tape loop holds most textures fine."],[],["Use a paper bag as a blindfold-free reach-in test if eyes won't stay shut."]]},
  {"id":"sq-zen-tray-gardens","title":"Zen Tray Gardens","altNames":["Mini Zen Garden","Sand Tray Garden","Calm Garden","Raked Sand Garden"],"type":"Quiet","place":"Both","ageMin":9,"ageMax":18,"durationMin":45,"groupMin":null,"groupMax":null,"energy":1,"prep":"Medium","blurb":"Campers build their own pocket-sized peaceful garden and rake calming patterns into the sand with a homemade tool.","materials":["A shallow tray, paper plate, or cardboard box lid per camper","Sand (or fine dirt, or baking soda as a clean indoor substitute), enough to fill each tray","Small smooth pebbles, 3-5 per camper","Cardboard and clothespins to build mini rakes","Pony beads, foam scraps, and twigs for decoration","Glue and scissors for building the rake","Paper to label gardens"],"materialTags":["Cardboard","Paper plates","Baking soda","Clothespins","Pony beads","Foam sheets","Glue","Scissors","Paper"],"steps":["Give each camper a tray and have them fill it with a smooth, even layer of sand (or baking soda indoors), tapping it level.","Make a mini rake by cutting comb-like teeth into a strip of cardboard and clipping it into a clothespin handle.","Place a few pebbles and small natural pieces in the tray as 'mountains' or 'islands,' arranging them in a way that feels balanced.","Drag the rake through the sand to create flowing lines, rippling them around the pebbles like water around stones.","Pause for a silent minute where campers slowly rake one calming pattern, noticing the sound and the motion as a mini meditation.","Share gardens around the circle, naming the feeling each design gives, then smooth them flat to prove the calm is in the making, not the keeping."],"notes":"Use baking soda or fine clean sand indoors to avoid grit everywhere, and put trays on paper to catch spills. The real value is the slow raking, so protect the silent minute and keep your directions low and unhurried. To scale up for grades 7-12, introduce the idea behind real Japanese zen gardens, challenge them to convey a specific emotion through pattern alone, and have them write a short reflection on what raking felt like.","safety":"Remind campers to keep sand and baking soda out of eyes and away from faces, never to throw it, and to wash hands after, especially before snacks.","ages":["g46","g79","g1012"],"rating":0,"links":[{"label":"How to Make a DIY Zen Garden Sand Tray for Kids — The Artful Parent","url":"https://artfulparent.com/diy-zen-garden-sand-tray/"},{"label":"Little Bins for Little Hands: calm & sensory activities","url":"https://littlebinsforlittlehands.com/summer-camp-activities/"}],"variations":["Add a 'pattern challenge' where campers must rake a specific shape (a spiral, concentric rings, waves) cleanly.","Make it a shared 'group garden' on one large tray where each camper contributes a section that must flow into the next.","For grades 7-12, tie in the philosophy of zen gardens and require each design to express a named emotion, defended in a short written reflection.","Turn it into a calming-routine station campers can return to during rest hour to reset a busy mind."],"subsets":[["Tap the tray gently to settle the sand flat before raking."],["Cut the rake teeth shallow so they don't snap off.","A clothespin makes a comfortable handle."],["Odd numbers of stones tend to look more balanced than even."],[],["Lower your voice for the silent minute to set the mood."],[]]},
];
